changeSet.sql:
-- Helper: insert role for department by name (skips if either not found) INSERT INTO clinlims.department_role_map (test_section_id, role_id) SELECT ts.id, sr.id FROM clinlims.test_section ts, clinlims.system_role sr WHERE ts.name IN ( 'Bacteriology','Immunology','Tuberculosis Laboratory', 'Medical Laboratory','Virology and Vaccine Unit', 'Malaria and Neglected Tropical Disease (MNTD) Laboratory' ) AND sr.name IN ( 'Sample Collectors', 'Laboratory Technicians', 'QC Technician','Results Entry and Validator', 'Notebook Entry Creator','Lab Managers','Storage Manager' ) AND ts.is_active = 'Y' AND sr.active = true ON CONFLICT ON CONSTRAINT uq_department_role_map DO NOTHING;
-- Pathology: includes Aliquoting Technician and Archivist INSERT INTO clinlims.department_role_map (test_section_id, role_id) SELECT ts.id, sr.id FROM clinlims.test_section ts, clinlims.system_role sr WHERE ts.name = 'Pathology Laboratory' AND sr.name IN ( 'QC Technician','Results Entry and Validator', 'Notebook Entry Creator','Lab Managers', 'Aliquoting Technician','Archivist','Storage Manager' ) AND ts.is_active = 'Y' AND sr.active = true ON CONFLICT ON CONSTRAINT uq_department_role_map DO NOTHING;
-- Biorepository: includes Archivist INSERT INTO clinlims.department_role_map (test_section_id, role_id) SELECT ts.id, sr.id FROM clinlims.test_section ts, clinlims.system_role sr WHERE ts.name = 'Biorepository Laboratory' AND sr.name IN ( 'QC Technician','Notebook Entry Creator', 'Lab Managers','Storage Manager','Archivist' ) AND ts.is_active = 'Y' AND sr.active = true ON CONFLICT ON CONSTRAINT uq_department_role_map DO NOTHING;
-- Analytical labs: includes Analyst and Report Generator INSERT INTO clinlims.department_role_map (test_section_id, role_id) SELECT ts.id, sr.id FROM clinlims.test_section ts, clinlims.system_role sr WHERE ts.name IN ( 'Bioanalytical Laboratory','Bioequivalence Laboratory', 'Pharmaceuticals Laboratory' ) AND sr.name IN ( 'Analyst','QC Technician','Results Entry and Validator', 'Notebook Entry Creator','Lab Managers','Report Generator' ) AND ts.is_active = 'Y' AND sr.active = true ON CONFLICT ON CONSTRAINT uq_department_role_map DO NOTHING;
-- Traditional Medicine: includes Researchers INSERT INTO clinlims.department_role_map (test_section_id, role_id) SELECT ts.id, sr.id FROM clinlims.test_section ts, clinlims.system_role sr WHERE ts.name = 'Traditional & Modern Medicine Research Lab' AND sr.name IN ( 'Analyst','QC Technician','Researchers', 'Notebook Entry Creator','Lab Managers' ) AND ts.is_active = 'Y' AND sr.active = true ON CONFLICT ON CONSTRAINT uq_department_role_map DO NOTHING;
-- Genomics: no sample collection, focus on analysis INSERT INTO clinlims.department_role_map (test_section_id, role_id) SELECT ts.id, sr.id FROM clinlims.test_section ts, clinlims.system_role sr WHERE ts.name = 'Genomics & Bioinformatics Laboratory' AND sr.name IN ( 'Analyst','Researchers','Notebook Entry Creator', 'Lab Managers','Report Generator' ) AND ts.is_active = 'Y' AND sr.active = true ON CONFLICT ON CONSTRAINT uq_department_role_map DO NOTHING;
